patch:
diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index b6a80fef4217..b91f1b6c1ea1 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -583,6 +583,16 @@ static bool cmpExcludesZero(CmpInst::Predicate Pred, const Value *RHS) {
     return !TrueValues.contains(Zero);
   }

+  // Handle non-constant values with range information (e.g., function arguments
+  // with range attribute or instructions with range metadata).
+  // This enables recognizing that range(1, 0) excludes zero.
+  ConstantRange RHSRange = computeConstantRange(
+      RHS, ICmpInst::isSigned(Pred), /*UseInstrInfo*/ true,
+      /*AC*/ nullptr, /*CxtI*/ nullptr, /*DT*/ nullptr, 0);
+  ConstantRange TrueValues = ConstantRange::makeAllowedICmpRegion(Pred, RHSRange);
+  if (!TrueValues.contains(Zero))
+    return true;
+
   auto *VC = dyn_cast<ConstantDataVector>(RHS);
   if (VC == nullptr)
     return false;
@@ -596,7 +606,6 @@ static bool cmpExcludesZero(CmpInst::Predicate Pred, const Value *RHS) {
   }
   return true;
 }
-
 static void breakSelfRecursivePHI(const Use *U, const PHINode *PHI,
                                   Value *&ValOut, Instruction *&CtxIOut,
                                   const PHINode **PhiOut = nullptr) {
@@ -3971,6 +3980,38 @@ static bool isKnownNonEqual(const Value *V1, const Value *V2,
       match(V2, m_PtrToIntSameSize(Q.DL, m_Value(B))))
     return isKnownNonEqual(A, B, DemandedElts, Q, Depth + 1);

+  // If sub(ptrtoint(V1), ptrtoint(V2)) is known non-zero, then V1 != V2.
+  // This handles cases like: assume((ptrtoint p0) - (ptrtoint p1) == non-zero)
+  // implies p0 != p1.
+  if (V1->getType()->isPointerTy() && V2->getType()->isPointerTy()) {
+    auto m_PtrToIntV1 = m_CombineOr(m_PtrToInt(m_Specific(V1)),
+                                    m_Trunc(m_PtrToInt(m_Specific(V1))));
+    auto m_PtrToIntV2 = m_CombineOr(m_PtrToInt(m_Specific(V2)),
+                                    m_Trunc(m_PtrToInt(m_Specific(V2))));
+    // Look for sub(ptrtoint(V1), ptrtoint(V2)) or sub(ptrtoint(V2), ptrtoint(V1))
+    // and check if it's known non-zero.
+    for (auto &BB : *Q.CxtI->getFunction()) {
+      for (auto &Inst : BB) {
+        if (auto *BO = dyn_cast<BinaryOperator>(&Inst)) {
+          if (BO->getOpcode() != Instruction::Sub)
+            continue;
+          Value *Op0 = BO->getOperand(0);
+          Value *Op1 = BO->getOperand(1);
+          // Check if this is sub(ptrtoint(V1), ptrtoint(V2))
+          if (match(Op0, m_PtrToIntV1) && match(Op1, m_PtrToIntV2)) {
+            if (isKnownNonZero(BO, DemandedElts, Q, Depth + 1))
+              return true;
+          }
+          // Check if this is sub(ptrtoint(V2), ptrtoint(V1))
+          if (match(Op0, m_PtrToIntV2) && match(Op1, m_PtrToIntV1)) {
+            if (isKnownNonZero(BO, DemandedElts, Q, Depth + 1))
+              return true;
+          }
+        }
+      }
+    }
+  }
+
   if (isKnownNonEqualFromContext(V1, V2, Q, Depth))
     return true;

