{"command": "cd /app/data/auto-opt/utils/llvm-118106 && python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Analysis/ValueTracking.cpp 569 599 << 'CODEEOF'
static bool cmpExcludesZero(CmpInst::Predicate Pred, const Value *RHS) {
  // v u> y implies v != 0.
  if (Pred == ICmpInst::ICMP_UGT)
    return true;

  // Special-case v != 0 to also handle v != null.
  if (Pred == ICmpInst::ICMP_NE)
    return match(RHS, m_Zero());

  // All other predicates - rely on generic ConstantRange handling.
  const APInt *C;
  auto Zero = APInt::getZero(RHS->getType()->getScalarSizeInBits());
  if (match(RHS, m_APInt(C))) {
    ConstantRange TrueValues = ConstantRange::makeExactICmpRegion(Pred, *C);
    return !TrueValues.contains(Zero);
  }

  // Handle non-constant values with range information (e.g., function arguments
  // with range attribute or instructions with range metadata).
  // This enables recognizing that range(1, 0) excludes zero.
  ConstantRange RHSRange = computeConstantRange(
      RHS, ICmpInst::isSigned(Pred), /*UseInstrInfo*/ true,
      /*AC*/ nullptr, /*CxtI*/ nullptr, /*DT*/ nullptr, 0);
  ConstantRange TrueValues = ConstantRange::makeAllowedICmpRegion(Pred, RHSRange);
  if (!TrueValues.contains(Zero))
    return true;

  auto *VC = dyn_cast<ConstantDataVector>(RHS);
  if (VC == nullptr)
    return false;

  for (unsigned ElemIdx = 0, NElem = VC->getNumElements(); ElemIdx < NElem;
       ++ElemIdx) {
    ConstantRange TrueValues = ConstantRange::makeExactICmpRegion(
        Pred, VC->getElementAsAPInt(ElemIdx));
    if (TrueValues.contains(Zero))
      return false;
  }
  return true;
}
CODEEOF
